function storedLocale(): Locale {
  if (typeof window === "undefined") return "ja";
  try {
    const stored = window.localStorage.getItem(STORAGE_KEY);
    return stored === "en" || stored === "ja" ? stored : "ja";
  } catch {
    return "ja";
  }
}

export const locale = signal<Locale>(storedLocale());

export function setLocale(next: Locale): void {
  locale.value = next;
  if (typeof document !== "undefined") document.documentElement.lang = next;
  if (typeof window !== "undefined") {
    try { window.localStorage.setItem(STORAGE_KEY, next); } catch { /* Preferences may be blocked. */ }
  }
}

export function initializeI18n(): void {
  if (typeof document !== "undefined") document.documentElement.lang = locale.value;
}

export function t(key: TranslationKey, values?: Record<string, string | number>): string {
  let result: string = (locale.value === "en" ? en : ja)[key];
  if (!values) return result;
  for (const [name, value] of Object.entries(values)) result = result.replaceAll(`{${name}}`, String(value));
  return result;
}

